#include <bits/stdc++.h>
using namespace std;

const int N=2e5+10;

struct Edge{
    int t,v;
};

int n,m;
long long len,ans,dis[N];
vector<Edge> e[N];
int p,q,f[N];
bool b[N];

int dfs(int x,int lst){
    f[x]=lst;
    int res=x;
    for(auto [y,w]:e[x])
        if(y!=lst){
            dis[y]=dis[x]+w;
            int u=dfs(y,x);
            if(dis[u]>dis[res])
                res=u;
        }
    return res;
}

void dfs2(int x){
    b[x]=1;
    ans=max(ans,dis[x]);
    for(auto [y,w]:e[x])
        if(!b[y]){
            dis[y]=dis[x]+w;
            dfs2(y);
        }
}

int main(){
    scanf("%d%d",&n,&m);
    while(m--){
        int u,v,w;
        scanf("%d%d%d",&u,&v,&w);
        e[u].push_back({v,w});
        e[v].push_back({u,w});
    }
    p=dfs(1,0);
    dis[p]=0;
    q=dfs(p,0);
    len=dis[q];
    for(int i=q;i;i=f[i]){
        b[i]=1;
        dis[i]=min(dis[i],len-dis[i]);
    }
    for(int i=q;i;i=f[i])
        dfs2(i);
    printf("%lld",len+ans);
    return 0;
}
